"use client"

import { ViolinChart } from "@/components/ui/charts"

// Generate sample data
const generateData = (mean: number, std: number, n: number, seed: number) => {
  const values: number[] = []
  let s = seed
  for (let i = 0; i < n; i++) {
    s = (s * 9301 + 49297) % 233280
    const u1 = s / 233280
    s = (s * 9301 + 49297) % 233280
    const u2 = s / 233280
    const z = Math.sqrt(-2 * Math.log(u1 || 0.001)) * Math.cos(2 * Math.PI * u2)
    values.push(mean + std * z)
  }
  return values
}

// Small sample data for bean plot (showing individual points)
const data = [
  { category: "Control", values: generateData(50, 8, 30, 100), color: "#6366f1" },
  { category: "Treatment A", values: generateData(62, 10, 30, 200), color: "#8b5cf6" },
  { category: "Treatment B", values: generateData(58, 12, 30, 300), color: "#a855f7" },
]

export default function ViolinChartBean() {
  return (
    <ViolinChart
      data={data}
      variant="bean"
      showBoxPlot={false}
      showMedian
    />
  )
}
